option.value:
* {
    box-sizing: border-box;
}

:root {
    --bg: #f5f7fb;
    --surface: #ffffff;
    --text: #1f2937;
    --muted: #6b7280;
    --border: #dbe2ea;
    --primary: #2563eb;
    --primary-hover: #1d4ed8;
    --danger: #dc2626;
    --danger-hover: #b91c1c;
    --secondary: #6b7280;
    --secondary-hover: #4b5563;
    --success-soft: #ecfdf3;
}

body {
    margin: 0;
    font-family: "Inter", "Segoe UI", Roboto, Arial, sans-serif;
    background: var(--bg);
    color: var(--text);
    line-height: 1.45;
}

.page {
    min-height: 100vh;
    padding: 24px 16px 40px;
}

.container {
    width: 100%;
    max-width: 980px;
    margin: 0 auto;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 14px;
    padding: 24px;
    box-shadow: 0 8px 28px rgba(15, 23, 42, 0.06);
}

.app-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 12px;
    padding-bottom: 14px;
    border-bottom: 1px solid var(--border);
    margin-bottom: 20px;
}

.app-title {
    margin: 0;
    font-size: 1.35rem;
    font-weight: 700;
}

.app-subtitle {
    margin: 0;
    color: var(--muted);
    font-size: 0.95rem;
}

.nav {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    margin: 10px 0 18px;
}

h1,
h2,
h3 {
    margin: 0 0 14px;
}

p {
    margin: 10px 0;
}

a {
    color: var(--primary);
    text-decoration: none;
}

a:hover {
    text-decoration: underline;
}

.card {
    border: 1px solid var(--border);
    border-radius: 12px;
    background: #fff;
    padding: 16px;
    margin-bottom: 16px;
}

.form-grid {
    display: grid;
    gap: 12px;
    max-width: 520px;
}

label {
    display: block;
    font-weight: 600;
    margin-bottom: 6px;
}

input,
select,
textarea {
    width: 100%;
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 10px 12px;
    font-size: 0.95rem;
    background: #fff;
}

input:focus,
select:focus,
textarea:focus {
    outline: 2px solid #bfdbfe;
    border-color: #93c5fd;
}

.btn,
button {
    appearance: none;
    border: none;
    border-radius: 10px;
    padding: 10px 14px;
    font-size: 0.92rem;
    font-weight: 600;
    cursor: pointer;
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
}

.btn-primary,
button,
.btn {
    background: var(--primary);
    color: #fff;
}

.btn-primary:hover,
button:hover,
.btn:hover {
    background: var(--primary-hover);
}

.btn-danger {
    background: var(--danger);
    color: #fff;
}

.btn-danger:hover {
    background: var(--danger-hover);
}

.btn-warning {
    background: #d97706;
    color: #fff;
}

.btn-warning:hover {
    background: #b45309;
}

.btn-secondary {
    background: var(--secondary);
    color: #fff;
}

.btn-secondary:hover {
    background: var(--secondary-hover);
}

.actions {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    margin-top: 14px;
}

table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10px;
    overflow: hidden;
    border-radius: 10px;
}

th,
td {
    border: 1px solid var(--border);
    padding: 10px;
    text-align: left;
    vertical-align: top;
}

th {
    background: #f8fafc;
}

.error-text,
.field-error {
    color: #b91c1c;
    font-size: 0.9rem;
    margin-top: 4px;
    display: block;
}

.helper-text {
    color: var(--muted);
    font-size: 0.92rem;
}

.empty-state {
    color: var(--muted);
    background: #f8fafc;
    border: 1px dashed var(--border);
    padding: 12px;
    border-radius: 10px;
}

.success-soft {
    background: var(--success-soft);
    border: 1px solid #a7f3d0;
    border-radius: 10px;
    padding: 10px;
}

.inline-form {
    display: inline;
}

/* ========== Flash alert banners ========== */
.alert {
    padding: 12px 16px;
    border-radius: 10px;
    margin-bottom: 16px;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 8px;
}

.alert-success {
    background: #ecfdf5;
    border: 1px solid #a7f3d0;
    color: #065f46;
}

.alert-error {
    background: #fef2f2;
    border: 1px solid #fecaca;
    color: #991b1b;
}

/* ========== Active nav button ========== */
.btn.active,
a.btn.active {
    box-shadow: inset 0 0 0 2px rgba(0, 0, 0, 0.20);
    filter: brightness(0.88);
    cursor: default;
    pointer-events: none;
    text-decoration: none;
}

@media (max-width: 768px) {
    .container {
        padding: 16px;
    }

    .app-header {
        flex-direction: column;
        align-items: flex-start;
    }

    .nav,
    .actions {
        width: 100%;
    }

    .nav .btn,
    .actions .btn,
    .actions button,
    .form-grid button {
        width: 100%;
    }

    th,
    td {
        font-size: 0.9rem;
    }
}

